package aisuite

import "encoding/json"

type AISuite struct {
	Identification `json:",inline"`
	Description    string `json:"description"`
}

type Identification struct {
	SourceRegistry string `json:"sourceRegistry"`
	Name           string `json:"name"`
	ChartVersion   string `json:"chartVersion"`
}

// 同名套件，使用最新版本的 Description
type ProfileAISuite struct {
	Name        string          `json:"name"`
	Status      string          `json:"status"` // e.g. "deployed", "not_deployed"
	Description string          `json:"description"`
	Version     *AISuiteVersion `json:"version"`
	Namespace   string          `json:"namespace,omitempty"` // NameSpace字段仅对已部署的套件有意义，表示当前部署的命名空间
}

type AISuiteVersion struct {
	AppVersion     string `json:"appVersion"`
	ChartVersion   string `json:"chartVersion"`
	Revision       int    `json:"revision,omitempty"` // Revision字段仅对已部署的套件有意义，表示当前部署的版本修订号
	DisplayVersion string `json:"displayVersion"`
}

type CustomValues struct {
	Name  string `json:"name"`
	Value any    `json:"value"`
}

// --------- 前后端接口 ---------

type ListAISuitesReq struct {
	ClusterType string `form:"clusterType,default:normal" binding:"oneof=normal multiCloud"`
	ClusterCode string `form:"clusterCode" binding:"required"`
}

type ListAISuitesResp struct {
	Total int               `json:"total"`
	Data  []*ProfileAISuite `json:"data"`
}

type GetAISuiteReq struct {
	Name         string `uri:"name"`
	ClusterCode  string `form:"clusterCode" binding:"required"`
	ChartVersion string `form:"chartVersion"`
	Namespace    string `form:"namespace"`
}

type GetAISuiteResp struct {
	ProfileAISuite    *ProfileAISuite   `json:",inline"`
	InCluster         bool              `json:"inCluster"`
	MaxRevision       int               `json:"maxRevision,omitempty"` // MaxRevision字段仅对已部署的套件有意义，表示当前套件的最大版本修订号
	VersionList       []*AISuiteVersion `json:"versionList"`
	CustomValueSchema json.RawMessage   `json:"customValueSchema"`
}

type GetAISuiteReadmeReq struct {
	Name         string `uri:"name"`
	ChartVersion string `form:"chartVersion" binding:"required"`
}

type GetAISuiteReadmeResp struct {
	Readme string `json:"readme"`
}

type OperateAISuiteReq struct {
	Name         string          `uri:"name"`
	Action       string          `json:"action" binding:"required,oneof=install upgrade uninstall"`
	ClusterCode  string          `json:"clusterCode" binding:"required"`
	Namespace    string          `json:"namespace" binding:"required_unless=Action install"`      // Namespace字段仅在部署操作中有意义，表示要部署到的命名空间
	ChartVersion string          `json:"chartVersion" binding:"required_unless=Action uninstall"` // ChartVersion字段仅在部署和更新操作中有意义，表示要部署或更新到的版本
	CustomValues []*CustomValues `json:"customValues" binding:"required_unless=Action uninstall"` // CustomValues字段仅在部署和更新操作中有意义，表示用户自定义的值
}

type OperateAISuiteResp struct {
	Message string `json:"message"`
}

