package db

import (
	"time"

	"gorm.io/gorm"
)

type AISuiteCatalog struct {
	Id           uint64     `gorm:"primaryKey;autoIncrement"`
	Name         string     `gorm:"size:256;not null;uniqueIndex:uk_aisuite_catalog_name"`
	Description  string     `gorm:"type:text"`
	AppVersion   string     `gorm:"size:128"`
	ChartVersion string     `gorm:"size:128"`
	Digest       string     `gorm:"size:256"`
	PushTime     *time.Time `gorm:"index"`
	SyncedAt     time.Time  `gorm:"autoCreateTime"`
	Model
}

func (a *AISuiteCatalog) TableName() string {
	return "aisuite_catalog"
}

func (a *AISuiteCatalog) ReplaceAll(db *gorm.DB, catalogs []AISuiteCatalog) error {
	return db.Transaction(func(tx *gorm.DB) error {
		if err := tx.Session(&gorm.Session{AllowGlobalUpdate: true}).Delete(&AISuiteCatalog{}).Error; err != nil {
			return err
		}
		if len(catalogs) == 0 {
			return nil
		}
		return tx.Create(&catalogs).Error
	})
}

func (a *AISuiteCatalog) Gets(db *gorm.DB) ([]AISuiteCatalog, error) {
	catalogs := make([]AISuiteCatalog, 0)
	if err := db.Model(&AISuiteCatalog{}).Order("name").Find(&catalogs).Error; err != nil {
		return nil, err
	}
	return catalogs, nil
}

