90	func WrapPreload(db *gorm.DB, preloads ...PreloadParam) *gorm.DB {
91		for _, preload := range preloads {
92			var args interface{}
93			if len(preload.Args) == 1 {
94				args = preload.Args[0]
95			} else if len(preload.Args) > 1 {
96				argStr := ""
97				l := len(preload.Args)
98				for i, arg := range preload.Args {
99					argStr = argStr + fmt.Sprintf("%v", arg)
100					if i != l-1 {
101						argStr = argStr + " AND "
102					}
103				}
104				args = argStr
105			}
106			db = db.Preload(preload.Query, args)
107		}
108		return db
