func WrapLimitOffset(db *gorm.DB, size, current int) *gorm.DB {
	if current == 0 || size == 0 {
		return db
	}
	return db.Limit(size).Offset((current - 1) * size)
}

type PreloadParam struct {
	Query string
	Args  []interface{}
}

func NewDefaultArgs() []interface{} {
	return []interface{}{
		"is_deleted = 0",
	}
}

func NewPreloadParam(query string, args ...interface{}) PreloadParam {
	return PreloadParam{
		Query: query,
		Args:  args,
	}
}

func WrapPreload(db *gorm.DB, preloads ...PreloadParam) *gorm.DB {
	for _, preload := range preloads {
		var args interface{}
		if len(preload.Args) == 1 {
			args = preload.Args[0]
		} else if len(preload.Args) > 1 {
			argStr := ""
			l := len(preload.Args)
			for i, arg := range preload.Args {
				argStr = argStr + fmt.Sprintf("%v", arg)
				if i != l-1 {
					argStr = argStr + " AND "
				}
			}
			args = argStr
		}
		db = db.Preload(preload.Query, args)
	}
	return db
}

