568	func (c *Controller) listAISuitesInRegistryFromHarbor(ctx context.Context, suiteRegistry *db.Repository) ([]*aisuite.ProfileAISuite, error) {
569		reposInSuiteRegistry := make([]*model.Repository, 0)
570		seenRepo := make(map[string]struct{})
571		registryOpts := harbor.DefaultOptions().WithPageSize(100).WithPage(1)
572		for {
573			registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
574			if err != nil {
575				log.Errorf("failed to get registry client: %v", err)
576				return nil, err
577			}
578			repos, err := registryCli.GetClient().ListRepositories(ctx, suiteChartProject)
579			if err != nil {
580				log.Errorf("failed to list repositories in suite registry: %v", err)
581				return nil, err
582			}
583			for _, repo := range repos {
584				if _, exists := seenRepo[repo.Name]; exists {
585					continue
586				}
587				seenRepo[repo.Name] = struct{}{}
588				reposInSuiteRegistry = append(reposInSuiteRegistry, repo)
589			}
590			if int64(len(repos)) < registryOpts.PageSize {
591				break
592			}
593			registryOpts = registryOpts.WithPage(registryOpts.Page + 1)
594			if registryOpts.Page > 20 {
595				log.Errorf("too many repositories in suite registry, page: %d, pageSize: %d", registryOpts.Page, registryOpts.PageSize)
596				break
597			}
598		}
599	
600		aiSuites, err := filterAISuitesFromRepos(ctx, suiteRegistry, reposInSuiteRegistry)
601		if err != nil {
602			log.Errorf("failed to get AI Suites from repos: %v", err)
603			return nil, err
604		}
605		return aiSuites, nil
