610		c.catalogSyncMu.Lock()
611		defer c.catalogSyncMu.Unlock()
612		if time.Since(c.catalogLastSync) < catalogSyncInterval {
613			return c.catalogSyncError
614		}
615	
616		aiSuites, err := c.listAISuitesInRegistryFromHarbor(ctx, suiteRegistry)
617		if err != nil {
618			c.catalogSyncError = err
619			c.catalogLastSync = time.Now()
620			return err
621		}
622		catalogRows := make([]db.AISuiteCatalog, 0, len(aiSuites))
623		for _, suite := range aiSuites {
624			if suite == nil || suite.Version == nil {
625				continue
626			}
627			row := db.AISuiteCatalog{
628				Name:         suite.Name,
629				Description:  suite.Description,
630				AppVersion:   suite.Version.AppVersion,
631				ChartVersion: suite.Version.ChartVersion,
632				SyncedAt:     time.Now(),
633			}
634			catalogRows = append(catalogRows, row)
635		}
636	
637		err = new(db.AISuiteCatalog).ReplaceAll(c.db, catalogRows)
638		c.catalogSyncError = err
639		c.catalogLastSync = time.Now()
640		return err
641	}
