683	// 保留至少有一个 Chart 类型的 Artifact 的 Repo，其他的 Repo 都丢弃
684	func filterAISuitesFromRepos(ctx context.Context, suiteRegistry *db.Repository, repos []*model.Repository) ([]*aisuite.ProfileAISuite, error) {
685		optionsWithQuery := harbor.DefaultOptions().WithPageSize(1).WithPage(1).WithQuery("tags=~.,Type=" + chartArtifactType).WithSort("-push_time")
686		registryCli, err := harbor.GetRegistryClient(suiteRegistry, optionsWithQuery)
687		if err != nil {
688			log.Errorf("failed to get registry client: %v", err)
689			return nil, err
690		}
691		aiSuites := make([]*aisuite.ProfileAISuite, 0, len(repos))
692		if len(repos) == 0 {
693			return aiSuites, nil
694		}
695		const maxWorkers = 8
696		var wg sync.WaitGroup
697		var mu sync.Mutex
698		sem := make(chan struct{}, maxWorkers)
699	
700		for _, repo := range repos {
701			wg.Add(1)
