func (c *Controller) getAISuiteInCluster(clusterCode, name, chartVersion, namespace string) (*aisuite.GetAISuiteResp, error) {
	releaseInCluster, err := c.apiserverGetter.GetHelmReleaseByName(clusterCode, namespace, name)
	if err != nil {
		log.Errorf("failed to get helm release [%s:%s] in cluster %s: %v", namespace, name, clusterCode, err)
		return nil, fmt.Errorf("failed to get helm release in cluster: %w", err)
	}
	if releaseInCluster.Labels["DeployedBy"] != "TAPAISuite" {
		return nil, fmt.Errorf("helm release %s in namespace %s is not deployed by TAPAISuite", name, namespace)
	}
	profile := releaseElementToProfileAISuite(releaseInCluster)
	if chartVersion != "" && profile.Version.ChartVersion != chartVersion {
		return nil, fmt.Errorf("chart version mismatch for release %s in namespace %s: expected %s, got %s", name, namespace, chartVersion, profile.Version.ChartVersion)
	}
	versionList := make([]*aisuite.AISuiteVersion, 0)
	versionList = append(versionList, profile.Version)
	return &aisuite.GetAISuiteResp{
		ProfileAISuite: profile,
		InCluster:      true,
		MaxRevision:    releaseInCluster.Revision, // 目前还不做回滚功能，所以MaxRevision就是当前版本的Revision
		VersionList:    versionList,
	}, nil
}

func (c *Controller) listAISuitesInRegistry(ctx *gin.Context, suiteRegistry *db.Repository) ([]*aisuite.ProfileAISuite, error) {
	if suiteRegistry == nil {
		return nil, fmt.Errorf("suite registry is nil")
	}

	c.registryCacheMu.RLock()
	if time.Now().Before(c.registrySuitesExpire) && c.registrySuitesCache != nil {
		cached := cloneProfileAISuiteSlice(c.registrySuitesCache)
		c.registryCacheMu.RUnlock()
		return cached, nil
	}
	c.registryCacheMu.RUnlock()

	requestCtx := context.Background()
	if ctx != nil && ctx.Request != nil {
		requestCtx = ctx.Request.Context()
	}

	if err := c.syncAISuiteCatalogIfNeeded(requestCtx, suiteRegistry); err != nil {
		log.Warnf("failed to sync aisuite catalog, fallback to direct harbor query: %v", err)
	}

	aiSuites, err := c.listAISuitesFromCatalog()
	if err == nil {
		c.registryCacheMu.Lock()
		c.registrySuitesCache = cloneProfileAISuiteSlice(aiSuites)
		c.registrySuitesExpire = time.Now().Add(registryCacheTTL)
		c.registryCacheMu.Unlock()
		return aiSuites, nil
	}
	log.Warnf("failed to list aisuite catalog from db, fallback to direct harbor query: %v", err)

	aiSuites, err = c.listAISuitesInRegistryFromHarbor(requestCtx, suiteRegistry)
	if err != nil {
		return nil, err
	}
	c.registryCacheMu.Lock()
	c.registrySuitesCache = cloneProfileAISuiteSlice(aiSuites)
	c.registrySuitesExpire = time.Now().Add(registryCacheTTL)
	c.registryCacheMu.Unlock()

	return aiSuites, nil
}

func (c *Controller) listAISuitesInRegistryFromHarbor(ctx context.Context, suiteRegistry *db.Repository) ([]*aisuite.ProfileAISuite, error) {
	reposInSuiteRegistry := make([]*model.Repository, 0)
	seenRepo := make(map[string]struct{})
	registryOpts := harbor.DefaultOptions().WithPageSize(100).WithPage(1)
	for {
		registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
		if err != nil {
			log.Errorf("failed to get registry client: %v", err)
			return nil, err
		}
		repos, err := registryCli.GetClient().ListRepositories(ctx, suiteChartProject)
		if err != nil {
			log.Errorf("failed to list repositories in suite registry: %v", err)
			return nil, err
		}
		for _, repo := range repos {
			if _, exists := seenRepo[repo.Name]; exists {
				continue
			}
			seenRepo[repo.Name] = struct{}{}
			reposInSuiteRegistry = append(reposInSuiteRegistry, repo)
		}
		if int64(len(repos)) < registryOpts.PageSize {
			break
		}
		registryOpts = registryOpts.WithPage(registryOpts.Page + 1)
		if registryOpts.Page > 20 {
			log.Errorf("too many repositories in suite registry, page: %d, pageSize: %d", registryOpts.Page, registryOpts.PageSize)
			break
		}
	}

	aiSuites, err := filterAISuitesFromRepos(ctx, suiteRegistry, reposInSuiteRegistry)
	if err != nil {
		log.Errorf("failed to get AI Suites from repos: %v", err)
		return nil, err
	}
	return aiSuites, nil

}

func (c *Controller) syncAISuiteCatalogIfNeeded(ctx context.Context, suiteRegistry *db.Repository) error {
	c.catalogSyncMu.Lock()
	defer c.catalogSyncMu.Unlock()
	if time.Since(c.catalogLastSync) < catalogSyncInterval {
		return c.catalogSyncError
	}

	aiSuites, err := c.listAISuitesInRegistryFromHarbor(ctx, suiteRegistry)
	if err != nil {
		c.catalogSyncError = err
		c.catalogLastSync = time.Now()
		return err
	}
	catalogRows := make([]db.AISuiteCatalog, 0, len(aiSuites))
	for _, suite := range aiSuites {
		if suite == nil || suite.Version == nil {
			continue
		}
		row := db.AISuiteCatalog{
			Name:         suite.Name,
			Description:  suite.Description,
			AppVersion:   suite.Version.AppVersion,
			ChartVersion: suite.Version.ChartVersion,
			SyncedAt:     time.Now(),
		}
		catalogRows = append(catalogRows, row)
	}

	err = new(db.AISuiteCatalog).ReplaceAll(c.db, catalogRows)
	c.catalogSyncError = err
	c.catalogLastSync = time.Now()
	return err
}

func (c *Controller) listAISuitesFromCatalog() ([]*aisuite.ProfileAISuite, error) {
	catalogRows, err := new(db.AISuiteCatalog).Gets(c.db)
	if err != nil {
		return nil, err
	}

	aiSuites := make([]*aisuite.ProfileAISuite, 0, len(catalogRows))
	for _, row := range catalogRows {
		appVersion := row.AppVersion
		if appVersion == "" {
			appVersion = "devEdition"
		}
		displayVersion := getDisplayVersion(appVersion, row.ChartVersion)
		description := row.Description
		if description == "" {
			description = fmt.Sprintf("AI套件: %s:%s", row.Name, displayVersion)
		}
		aiSuites = append(aiSuites, &aisuite.ProfileAISuite{
			Name:        row.Name,
			Description: description,
			Status:      deployStatusUndeployed,
			Version: &aisuite.AISuiteVersion{
				AppVersion:     appVersion,
				ChartVersion:   row.ChartVersion,
				DisplayVersion: displayVersion,
			},
		})
	}
	return aiSuites, nil
}

func cloneProfileAISuiteSlice(in []*aisuite.ProfileAISuite) []*aisuite.ProfileAISuite {
	if in == nil {
		return nil
	}
	out := make([]*aisuite.ProfileAISuite, len(in))
	copy(out, in)
	return out
}

// 保留至少有一个 Chart 类型的 Artifact 的 Repo，其他的 Repo 都丢弃
func filterAISuitesFromRepos(ctx context.Context, suiteRegistry *db.Repository, repos []*model.Repository) ([]*aisuite.ProfileAISuite, error) {
	optionsWithQuery := harbor.DefaultOptions().WithPageSize(1).WithPage(1).WithQuery("tags=~.,Type=" + chartArtifactType).WithSort("-push_time")
	registryCli, err := harbor.GetRegistryClient(suiteRegistry, optionsWithQuery)
	if err != nil {
		log.Errorf("failed to get registry client: %v", err)
		return nil, err
	}
	aiSuites := make([]*aisuite.ProfileAISuite, 0, len(repos))
	if len(repos) == 0 {
		return aiSuites, nil
	}
	const maxWorkers = 8
	var wg sync.WaitGroup
	var mu sync.Mutex
	sem := make(chan struct{}, maxWorkers)

	for _, repo := range repos {
		wg.Add(1)
		go func() {
			defer wg.Done()
			sem <- struct{}{}
			defer func() { <-sem }()

			simpleRepoName := harbor.GetSimpleRepoName(repo.Name)
			charts, err := registryCli.GetClient().ListArtifacts(ctx, suiteChartProject, simpleRepoName)
			if err != nil {
				log.Warnf("failed to list artifacts in repo %s, error: %v", simpleRepoName, err)
				return
			}
			if len(charts) == 0 {
				return
			}
			chart := charts[0]
			description, ok := chart.ExtraAttrs["description"].(string)
			if !ok {
				description = "AI套件 —— " + simpleRepoName
			}
			appVersion, _ := chart.ExtraAttrs["appVersion"].(string)
			chartVersion, _ := chart.ExtraAttrs["version"].(string)
			suite := &aisuite.ProfileAISuite{
				Name:        simpleRepoName,
				Description: description,
				Status:      deployStatusUndeployed,
				Version: &aisuite.AISuiteVersion{
					AppVersion:     appVersion,
					ChartVersion:   chartVersion,
					DisplayVersion: appVersion + "@" + chartVersion,
				},
			}
			mu.Lock()
			aiSuites = append(aiSuites, suite)
			mu.Unlock()
		}()
	}
	wg.Wait()
	return aiSuites, nil
}

